    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // Create observer nodes
    auto direct_observer = std::make_shared<NamedObserverNode>("direct");
    auto transitive_observer = std::make_shared<NamedObserverNode>("transitive");
    auto source_node = std::make_shared<NamedObserverNode>("source");

    // Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // Register nodes
    graph.registerNode(direct_observer);
    graph.registerNode(transitive_observer);
    graph.registerNode(source_node);

    // Set up direct observer relationship
    source_node->addObserver(direct_observer);

    // Set up transitive observer relationship (observer observes another observer)
    direct_observer->addObserver(transitive_observer);

    // Create set to store collected observers
    reaction::NodeSet collected_observers;

    // Collect observers from source node
    graph.collectObservers(source_node, collected_observers);

    // Check results
    bool has_direct = !collected_observers.find(direct_observer).empty();
    bool has_transitive = !collected_observers.find(transitive_observer).empty();

    return ObserverCollectionSummary{
        collected_observers.size(),
        has_direct,
        has_transitive
    };
}

}  // namespace test_reaction
```

**Explanation:**

1. **Node Creation**: We create three `NamedObserverNode` instances with distinct names.

2. **Graph Registration**: All nodes are registered with the singleton `ObserverGraph` instance.

3. **Relationship Setup**: 
   - Direct relationship: `source_node` observes `direct_observer`
   - Transitive relationship: `direct_observer` observes `transitive_observer`

4. **Observer Collection**: The `collectObservers` method traverses the observer graph starting from `source_node`, collecting all direct and transitive observers.

5. **Result Verification**: The function checks if both expected observers are present in the collected set and returns a summary of the results.

This implementation demonstrates proper usage of the reaction framework's observer pattern functionality, including direct and transitive observer relationships.

