    auto chainedExpr = reaction::make_binary_expr(
        reaction::MulOp{},
        negatedExpr,
        reaction::expr(varC)
    );

    // Get initial values
    int initialSum = std::get<int>(sumExpr());
    int initialNegated = std::get<int>(negatedExpr());
    int initialChained = std::get<int>(chainedExpr());

    // Update values to trigger recomputation
    varA.value(a + 10);
    varC.value(c + 5);

    // Get updated values
    int updatedSum = std::get<int>(sumExpr());
    int updatedNegated = std::get<int>(negatedExpr());
    int updatedChained = std::get<int>(chainedExpr());

    return RawExpressionSnapshot{
        .initialSum = initialSum,
        .initialNegatedSum = initialNegated,
        .initialChainedValue = initialChained,
        .updatedSum = updatedSum,
        .updatedNegatedSum = updatedNegated,
        .updatedChainedValue = updatedChained
    };
}

